+    // ── MVCC WAL integration tests ───────────────────────────────────────
+
+    #[test]
+    fn open_options_default_has_no_wal() {
+        let opts = OpenOptions::default();
+        assert!(opts.mvcc_wal_path.is_none());
+        assert_eq!(
+            opts.mvcc_replay_policy,
+            ffs_mvcc::wal_replay::TailPolicy::TruncateToLastGood
+        );
+    }
