+    #[test]
+    fn mvcc_wal_recovery_none_without_wal_path() {
+        let image = build_ext4_image(1);
+        let dev = TestDevice::from_vec(image);
+        let cx = Cx::for_testing();
+        let opts = OpenOptions {
+            skip_validation: true,
+            ..OpenOptions::default()
+        };
